// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Like_Dislike {
    function Like_count (uint _like, uint _dislike) public pure  returns (uint) {
    return _like + _dislike;
}
    function Like_percentage (uint _like, uint _dislike) public pure returns (uint) {
        return (_like * 100) / (_like + _dislike);
    }
}

